import { useState } from "react";

const kategoriler = [
  {
    baslik: "Cep Telefonu-Aksesuar",
    altKategoriler: [
      "Apple Telefonlar",
      "Android Telefonlar",
      "Yapay Zeka (AI) Telefonlar",
      "Giyilebilir Teknolojiler",
      "Aksesuarlar",
      "Tuşlu Telefonlar",
      "Yenilenmiş Telefonlar",
      "5G Destekli Akıllı Telefonlar"
    ],
  },
  {
    baslik: "Bilgisayar-Tablet",
    altKategoriler: [
      "Masaüstü Bilgisayarlar",
      "Dizüstü Bilgisayarlar",
      "Tabletler",
      "Modem & Network Ürünleri",
      "Veri Depolama Ürünleri",
      "Bilgisayar Çevre Birimleri",
      "Tablet Aksesuarları"
    ],
  },
  {
    baslik: "Elektrikli Ev Aletleri",
    altKategoriler: [],
  },
  {
    baslik: "Sağlık-Kişisel Bakım",
    altKategoriler: [],
  },
  {
    baslik: "Hobi-Oyun",
    altKategoriler: [],
  },
  {
    baslik: "TV-Ses Sistemleri",
    altKategoriler: [],
  },
  {
    baslik: "Ev-Yaşam",
    altKategoriler: [],
  },
];

export default function Kategoriler() {
  const [acilan, setAcilan] = useState<string | null>(null);

  return (
    <div className="flex gap-6 mt-4 relative overflow-x-auto whitespace-nowrap border-y py-2">
      {kategoriler.map((kat, i) => (
        <div
          key={i}
          className="relative group"
          onMouseEnter={() => setAcilan(kat.baslik)}
          onMouseLeave={() => setAcilan(null)}
        >
          <button className="font-semibold px-2 hover:text-yellow-600 transition">
            {kat.baslik}
          </button>
          {kat.altKategoriler.length > 0 && acilan === kat.baslik && (
            <div className="absolute left-0 top-full mt-2 bg-white shadow-lg border rounded z-50 w-64 p-4">
              <ul className="space-y-1 text-sm text-gray-700">
                {kat.altKategoriler.map((alt, j) => (
                  <li
                    key={j}
                    className="hover:text-blue-600 cursor-pointer"
                  >
                    {alt}
                  </li>
                ))}
              </ul>
            </div>
          )}
        </div>
      ))}
    </div>
  );
}
